import { useState, useRef } from "react";
import { useTranslation } from "react-i18next";
import { supabase } from "@/integrations/supabase/client";
import { useQueryClient } from "@tanstack/react-query";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Checkbox } from "@/components/ui/checkbox";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { useToast } from "@/hooks/use-toast";
import { Search, Loader2, MapPin, Import, BookOpen, ImageIcon, AlertTriangle, CheckCircle2, Brain, Flame, ArrowLeft, Database, RefreshCw, Utensils, StopCircle } from "lucide-react";
import { Progress } from "@/components/ui/progress";
import { Input } from "@/components/ui/input";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Link } from "react-router-dom";
import { Switch } from "@/components/ui/switch";
import { Label } from "@/components/ui/label";

interface DiscoveredRestaurant {
  name: string;
  address: string;
  cuisine_type: string;
  city: string;
  source?: "perplexity" | "firecrawl";
  source_platform?: string;
  google_verified?: boolean;
  corrected_address?: string;
  verified?: boolean;
}

const CITIES = [
  "all",
  "Lisboa", "Porto", "Faro", "Coimbra", "Braga", "Aveiro", "Leiria",
  "Setúbal", "Almada", "Amadora", "Cascais", "Sintra", "Oeiras", "Odivelas",
  "Funchal", "Guimarães", "Viseu", "Évora", "Vila Nova de Gaia", "Matosinhos",
  "Barreiro", "Seixal", "Loures", "Portimão", "Albufeira", "Lagos",
  "Caldas da Rainha", "Torres Vedras", "Santarém", "Viana do Castelo",
];

export default function AdminDiscoverRestaurants() {
  const { t } = useTranslation();
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const [selectedCity, setSelectedCity] = useState("all");
  const [searchKeyword, setSearchKeyword] = useState("");
  const [isSearching, setIsSearching] = useState(false);
  const [isImporting, setIsImporting] = useState(false);
  const [isGeneratingStories, setIsGeneratingStories] = useState(false);
  const [discovered, setDiscovered] = useState<DiscoveredRestaurant[]>([]);
  const [selectedItems, setSelectedItems] = useState<Set<number>>(new Set());
  const [skipCache, setSkipCache] = useState(false);
  const [searchStats, setSearchStats] = useState<{
    total_discovered: number;
    duplicates_filtered: number;
    city_results?: Record<string, number>;
    verified_count?: number;
    source_stats?: { perplexity: number; firecrawl: number };
    platform_stats?: Record<string, number>;
    cache_hits?: number;
    search_error?: string;
  } | null>(null);
  const [importResults, setImportResults] = useState<{
    imported: number;
    failed: number;
  } | null>(null);
  const [importedIds, setImportedIds] = useState<string[]>([]);
  const [storyProgress, setStoryProgress] = useState({ current: 0, total: 0 });
  const [storyResult, setStoryResult] = useState<{ processed: number } | null>(null);
  const [isFetchingPhotos, setIsFetchingPhotos] = useState(false);
  const [photoProgress, setPhotoProgress] = useState({ current: 0, total: 0 });
  const [photoResult, setPhotoResult] = useState<{ success: number; failed: number } | null>(null);
  const abortControllerRef = useRef<AbortController | null>(null);

  const handleSearch = async () => {
    setIsSearching(true);
    setDiscovered([]);
    setSelectedItems(new Set());
    setSearchStats(null);
    setImportResults(null);

    const controller = new AbortController();
    abortControllerRef.current = controller;

    try {
      const { data, error } = await supabase.functions.invoke("discover-asian-restaurants", {
        body: { city: selectedCity, mode: "search", keyword: searchKeyword.trim() || undefined, skip_cache: skipCache },
      });

      if (controller.signal.aborted) return;
      if (error) throw error;

      const restaurants: DiscoveredRestaurant[] = data.restaurants || [];
      setDiscovered(restaurants);
      setSearchStats({
        total_discovered: data.total_discovered,
        duplicates_filtered: data.duplicates_filtered,
        city_results: data.city_results,
        verified_count: data.verified_count,
        source_stats: data.source_stats,
        platform_stats: data.platform_stats,
        cache_hits: data.cache_hits,
        search_error: data.search_error,
      });
      setSelectedItems(new Set(
        restaurants.map((r, i) => (r.google_verified !== false) ? i : -1).filter(i => i >= 0)
      ));
    } catch (e) {
      if (controller.signal.aborted) {
        toast({ title: "搜索已终止", description: "已手动停止搜索" });
        return;
      }
      toast({
        title: "搜索失败",
        description: e instanceof Error ? e.message : "Unknown error",
        variant: "destructive",
      });
    } finally {
      abortControllerRef.current = null;
      setIsSearching(false);
    }
  };

  const handleStopSearch = () => {
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
      abortControllerRef.current = null;
      setIsSearching(false);
    }
  };

  const handleImport = async () => {
    if (selectedItems.size === 0) return;
    setIsImporting(true);

    try {
      const selectedRestaurants = [...selectedItems].map(i => {
        const r = discovered[i];
        return {
          ...r,
          address: (r.google_verified === false && r.corrected_address) ? r.corrected_address : r.address,
        };
      });

      const { data, error } = await supabase.functions.invoke("discover-asian-restaurants", {
        body: { mode: "import", restaurants: selectedRestaurants },
      });

      if (error) throw error;

      setImportResults({ imported: data.imported, failed: data.failed });
      const successIds = (data.results || []).filter((r: any) => r.success).map((r: any) => r.id);
      setImportedIds(successIds);
      queryClient.invalidateQueries({ queryKey: ["admin-restaurants"] });

      toast({ title: "导入完成", description: `成功导入 ${data.imported} 家餐厅` });
    } catch (e) {
      toast({ title: "导入失败", description: e instanceof Error ? e.message : "Unknown error", variant: "destructive" });
    } finally {
      setIsImporting(false);
    }
  };

  const handleGenerateStories = async () => {
    setIsGeneratingStories(true);
    setStoryProgress({ current: 0, total: 0 });
    setStoryResult(null);

    try {
      if (importedIds.length === 0) {
        toast({ title: "没有已导入的餐厅可生成故事" });
        setIsGeneratingStories(false);
        return;
      }

      const total = importedIds.length;
      setStoryProgress({ current: 0, total });
      const batchSize = 5;
      let processed = 0;

      for (let i = 0; i < total; i += batchSize) {
        const batch = importedIds.slice(i, i + batchSize);
        const { data, error } = await supabase.functions.invoke("generate-store-stories", {
          body: { restaurant_ids: batch, mode: "story", no_brand: true },
        });
        if (error) { console.error("Story generation error:", error); continue; }
        processed += data?.updated || 0;
        setStoryProgress({ current: Math.min(i + batchSize, total), total });
        if (data?.processed === 0) break;
        await new Promise(r => setTimeout(r, 2000));
      }

      setStoryResult({ processed });
      toast({ title: "✅ 建筑故事生成完成", description: `已为 ${processed} 家餐厅生成建筑故事` });
    } catch (e) {
      toast({ title: "生成失败", description: e instanceof Error ? e.message : "Unknown error", variant: "destructive" });
    } finally {
      setIsGeneratingStories(false);
    }
  };

  const handleFetchPhotos = async () => {
    setIsFetchingPhotos(true);
    setPhotoProgress({ current: 0, total: 0 });
    setPhotoResult(null);

    try {
      if (importedIds.length === 0) {
        toast({ title: "没有已导入的餐厅可抓取照片" });
        setIsFetchingPhotos(false);
        return;
      }

      const total = importedIds.length;
      setPhotoProgress({ current: 0, total });
      const batchSize = 5;
      let successCount = 0;
      let failedCount = 0;

      for (let i = 0; i < total; i += batchSize) {
        const ids = importedIds.slice(i, i + batchSize);
        const { data, error } = await supabase.functions.invoke("fetch-place-photos", {
          body: { restaurant_ids: ids, limit: batchSize, photo_index: 0 },
        });

        if (!error && data?.results) {
          const batchSuccess = data.results.filter((r: any) => r.status === "success").length;
          const batchNoPhoto = data.results.filter((r: any) => r.status === "no_photos").map((r: any) => r.id);
          successCount += batchSuccess;

          if (batchNoPhoto.length > 0) {
            const { data: svData } = await supabase.functions.invoke("fetch-place-photos", {
              body: { restaurant_ids: batchNoPhoto, limit: batchNoPhoto.length, use_street_view: true },
            });
            if (svData?.results) {
              successCount += svData.results.filter((r: any) => r.status === "success").length;
              failedCount += svData.results.filter((r: any) => r.status !== "success").length;
            }
          }
          failedCount += data.results.filter((r: any) => r.status !== "success" && !batchNoPhoto.includes(r.id)).length;
        }

        setPhotoProgress({ current: Math.min(i + batchSize, total), total });
        await new Promise(r => setTimeout(r, 1000));
      }

      setPhotoResult({ success: successCount, failed: failedCount });
      toast({ title: "✅ 照片抓取完成", description: `成功 ${successCount} 家，失败 ${failedCount} 家` });
      queryClient.invalidateQueries({ queryKey: ["admin-restaurants"] });
    } catch (e) {
      toast({ title: "抓取失败", description: e instanceof Error ? e.message : "Unknown error", variant: "destructive" });
    } finally {
      setIsFetchingPhotos(false);
    }
  };

  const toggleItem = (index: number) => {
    setSelectedItems(prev => {
      const next = new Set(prev);
      if (next.has(index)) next.delete(index);
      else next.add(index);
      return next;
    });
  };

  const toggleAll = () => {
    if (selectedItems.size === discovered.length) {
      setSelectedItems(new Set());
    } else {
      setSelectedItems(new Set(discovered.map((_, i) => i)));
    }
  };

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center gap-3">
        <Link to="/admin/restaurants">
          <Button variant="ghost" size="icon">
            <ArrowLeft className="h-5 w-5" />
          </Button>
        </Link>
        <div>
          <h1 className="text-2xl font-bold flex items-center gap-2">
            <Search className="h-6 w-6" />
            搜索亚洲餐厅 (葡萄牙)
          </h1>
          <p className="text-sm text-muted-foreground mt-1">
            🤖 Perplexity AI + 🔎 Firecrawl Search (Uber Eats / TheFork / Glovo) → 📍 Google Places 验证
          </p>
        </div>
      </div>

      {/* Search controls */}
      <Card>
        <CardContent className="pt-6 space-y-3">
          <div className="flex flex-col sm:flex-row gap-2">
            <Select value={selectedCity} onValueChange={setSelectedCity}>
              <SelectTrigger className="w-full sm:w-[180px]">
                <SelectValue placeholder="选择城市" />
              </SelectTrigger>
              <SelectContent>
                {CITIES.map(city => (
                  <SelectItem key={city} value={city}>
                    {city === "all" ? "🇵🇹 全部城市" : city}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
            <Input
              placeholder="关键词（如：ramen, sushi, 火锅）"
              value={searchKeyword}
              onChange={(e) => setSearchKeyword(e.target.value)}
              className="flex-1"
              onKeyDown={(e) => e.key === "Enter" && !isSearching && handleSearch()}
            />
            {isSearching ? (
              <Button onClick={handleStopSearch} variant="destructive" className="sm:w-auto">
                <StopCircle className="mr-2 h-4 w-4" />终止搜索
              </Button>
            ) : (
              <Button onClick={handleSearch} className="sm:w-auto">
                <Search className="mr-2 h-4 w-4" />搜索
              </Button>
            )}
          </div>
          <div className="flex items-center gap-2">
            <Switch id="skip-cache" checked={skipCache} onCheckedChange={setSkipCache} />
            <Label htmlFor="skip-cache" className="text-xs text-muted-foreground cursor-pointer">
              <RefreshCw className="h-3 w-3 inline mr-1" />
              跳过缓存（强制重新搜索，缓存有效期3天）
            </Label>
          </div>
        </CardContent>
      </Card>

      {/* Loading state */}
      {isSearching && (
        <Card>
          <CardContent className="flex flex-col items-center justify-center py-12 gap-3">
            <Loader2 className="h-10 w-10 animate-spin text-primary" />
            <p className="text-muted-foreground">
              正在搜索{selectedCity === "all" ? "全葡萄牙" : selectedCity}的亚洲餐厅...
            </p>
            <p className="text-xs text-muted-foreground">
              Perplexity AI + Firecrawl Search (3个平台) → Google Places 验证
            </p>
            {selectedCity === "all" && (
              <p className="text-xs text-muted-foreground">搜索30个城市可能需要2-5分钟（有缓存时更快）</p>
            )}
          </CardContent>
        </Card>
      )}

      {/* Search stats */}
      {searchStats && !isSearching && (
        <Card>
          <CardContent className="pt-6 space-y-3">
            <div className="flex gap-4 text-sm flex-wrap">
              <span className="text-muted-foreground">发现: <strong className="text-foreground">{searchStats.total_discovered}</strong></span>
              <span className="text-muted-foreground">已存在: <strong className="text-foreground">{searchStats.duplicates_filtered}</strong></span>
              <span className="text-muted-foreground">新增: <strong className="text-foreground">{discovered.length}</strong></span>
              {searchStats.verified_count !== undefined && (
                <span className="text-emerald-600 dark:text-emerald-400 font-medium flex items-center gap-1">
                  <CheckCircle2 className="h-3.5 w-3.5" />
                  Google验证: {searchStats.verified_count}/{discovered.length}
                </span>
              )}
            </div>
            <div className="flex gap-4 text-xs text-muted-foreground flex-wrap">
              {searchStats.source_stats && (
                <>
                  <span className="flex items-center gap-1">
                    <Brain className="h-3 w-3 text-violet-500" />
                    Perplexity: {searchStats.source_stats.perplexity}
                  </span>
                  <span className="flex items-center gap-1">
                    <Search className="h-3 w-3 text-orange-500" />
                    Firecrawl: {searchStats.source_stats.firecrawl}
                  </span>
                </>
              )}
              {searchStats.platform_stats && Object.keys(searchStats.platform_stats).length > 0 && (
                <>
                  {searchStats.platform_stats.ubereats != null && (
                    <span className="flex items-center gap-1">
                      <Utensils className="h-3 w-3" /> UberEats: {searchStats.platform_stats.ubereats}
                    </span>
                  )}
                  {searchStats.platform_stats.thefork != null && (
                    <span className="flex items-center gap-1">
                      <Utensils className="h-3 w-3" /> TheFork: {searchStats.platform_stats.thefork}
                    </span>
                  )}
                  {searchStats.platform_stats.glovo != null && (
                    <span className="flex items-center gap-1">
                      <Utensils className="h-3 w-3" /> Glovo: {searchStats.platform_stats.glovo}
                    </span>
                  )}
                </>
              )}
              {(searchStats.cache_hits ?? 0) > 0 && (
                <span className="flex items-center gap-1 text-blue-500">
                  <Database className="h-3 w-3" />
                  缓存命中: {searchStats.cache_hits} 城市
                </span>
              )}
            </div>
            {searchStats.search_error && (
              <div className="p-3 rounded-md bg-destructive/10 border border-destructive/20 text-sm text-destructive flex items-start gap-2">
                <AlertTriangle className="h-4 w-4 mt-0.5 flex-shrink-0" />
                <div>
                  <p className="font-medium">API 错误</p>
                  <p className="text-xs mt-1 opacity-80">{searchStats.search_error}</p>
                </div>
              </div>
            )}
          </CardContent>
        </Card>
      )}

      {/* Results list */}
      {discovered.length > 0 && !isSearching && (
        <Card>
          <CardHeader className="pb-3">
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-2">
                <Checkbox
                  checked={selectedItems.size === discovered.length}
                  onCheckedChange={toggleAll}
                />
                <CardTitle className="text-base">全选 ({selectedItems.size}/{discovered.length})</CardTitle>
              </div>
              <Button onClick={handleImport} disabled={isImporting || selectedItems.size === 0}>
                {isImporting ? (
                  <><Loader2 className="mr-2 h-4 w-4 animate-spin" />导入中...</>
                ) : (
                  <><Import className="mr-2 h-4 w-4" />导入 ({selectedItems.size})</>
                )}
              </Button>
            </div>
          </CardHeader>
          <CardContent className="p-0">
            <div className="max-h-[60vh] overflow-y-auto divide-y">
              {discovered.map((r, i) => {
                const isVerified = r.google_verified !== false;
                return (
                  <div
                    key={i}
                    className={`flex items-start gap-3 px-4 py-3 hover:bg-muted/50 cursor-pointer transition-colors ${!isVerified ? "opacity-60 bg-destructive/5" : ""}`}
                    onClick={() => toggleItem(i)}
                  >
                    <Checkbox checked={selectedItems.has(i)} className="mt-1" />
                    <div className="flex-1 min-w-0">
                      <div className="font-medium text-sm flex items-center gap-1.5">
                        {!isVerified ? (
                          <AlertTriangle className="h-3.5 w-3.5 text-destructive flex-shrink-0" />
                        ) : (
                          <CheckCircle2 className="h-3.5 w-3.5 text-emerald-600 dark:text-emerald-400 flex-shrink-0" />
                        )}
                        <span className="truncate">{r.name}</span>
                      </div>
                      <div className="text-xs text-muted-foreground flex items-center gap-1 mt-0.5">
                        <MapPin className="h-3 w-3 flex-shrink-0" />
                        <span className={`truncate ${!isVerified ? "line-through" : ""}`}>{r.address}</span>
                      </div>
                      {!isVerified && r.corrected_address && (
                        <div className="text-xs text-emerald-600 dark:text-emerald-400 flex items-center gap-1 mt-0.5">
                          <MapPin className="h-3 w-3 flex-shrink-0" />
                          <span className="truncate">→ {r.corrected_address}</span>
                        </div>
                      )}
                    </div>
                    <div className="flex flex-col items-end gap-1 flex-shrink-0">
                      <Badge variant="secondary" className="text-xs">
                        {r.cuisine_type}
                      </Badge>
                      <div className="flex items-center gap-1">
                        {r.source === "perplexity" && (
                          <Badge variant="outline" className="text-[10px] px-1.5 py-0 h-4 border-violet-300 text-violet-600 dark:text-violet-400">
                            <Brain className="h-2.5 w-2.5 mr-0.5" />AI
                          </Badge>
                        )}
                        {r.source === "firecrawl" && (
                          <Badge variant="outline" className="text-[10px] px-1.5 py-0 h-4 border-orange-300 text-orange-600 dark:text-orange-400">
                            <Search className="h-2.5 w-2.5 mr-0.5" />FC
                          </Badge>
                        )}
                        {isVerified ? (
                          <Badge variant="outline" className="text-[10px] px-1.5 py-0 h-4 border-emerald-300 text-emerald-600 dark:text-emerald-400">
                            <CheckCircle2 className="h-2.5 w-2.5 mr-0.5" />G✓
                          </Badge>
                        ) : (
                          <Badge variant="outline" className="text-[10px] px-1.5 py-0 h-4 border-destructive/30 text-destructive">
                            G✗
                          </Badge>
                        )}
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          </CardContent>
        </Card>
      )}

      {/* Import results & post-import actions */}
      {importResults && (
        <Card>
          <CardContent className="pt-6 space-y-3">
            <div className="text-sm font-medium">
              ✅ 已导入 {importResults.imported} 家 | ❌ 失败 {importResults.failed} 家
            </div>

            {storyResult ? (
              <div className="p-3 rounded-md bg-emerald-500/10 border border-emerald-500/20 text-sm text-emerald-700 dark:text-emerald-400 font-medium">
                🎉 建筑故事生成完成！共处理 {storyResult.processed} 家餐厅
              </div>
            ) : (
              <Button variant="outline" onClick={handleGenerateStories} disabled={isGeneratingStories}>
                {isGeneratingStories ? (
                  <><Loader2 className="mr-2 h-4 w-4 animate-spin" />生成建筑故事中...</>
                ) : (
                  <><BookOpen className="mr-2 h-4 w-4" />为已导入餐厅生成故事 ({importedIds.length})</>
                )}
              </Button>
            )}

            {isGeneratingStories && storyProgress.total > 0 && (
              <div className="space-y-1">
                <Progress value={(storyProgress.current / storyProgress.total) * 100} />
                <div className="text-xs text-muted-foreground">{storyProgress.current} / {storyProgress.total}</div>
              </div>
            )}

            {photoResult ? (
              <div className="p-3 rounded-md bg-primary/10 border border-primary/20 text-sm text-primary font-medium">
                📷 照片抓取完成！成功 {photoResult.success} 家，失败 {photoResult.failed} 家
              </div>
            ) : (
              <Button variant="outline" onClick={handleFetchPhotos} disabled={isFetchingPhotos}>
                {isFetchingPhotos ? (
                  <><Loader2 className="mr-2 h-4 w-4 animate-spin" />抓取照片中...</>
                ) : (
                  <><ImageIcon className="mr-2 h-4 w-4" />为已导入餐厅抓取照片 ({importedIds.length})</>
                )}
              </Button>
            )}

            {isFetchingPhotos && photoProgress.total > 0 && (
              <div className="space-y-1">
                <Progress value={(photoProgress.current / photoProgress.total) * 100} />
                <div className="text-xs text-muted-foreground">{photoProgress.current} / {photoProgress.total}</div>
              </div>
            )}
          </CardContent>
        </Card>
      )}

      {/* Quick tools when no search active */}
      {!importResults && !isSearching && discovered.length === 0 && (
        <Card>
          <CardHeader>
            <CardTitle className="text-base">快捷工具</CardTitle>
          </CardHeader>
          <CardContent className="space-y-3">
            {photoResult ? (
              <div className="p-3 rounded-md bg-primary/10 border border-primary/20 text-sm text-primary font-medium">
                📷 照片抓取完成！成功 {photoResult.success} 家，失败 {photoResult.failed} 家
              </div>
            ) : (
              <Button variant="outline" onClick={handleFetchPhotos} disabled={isFetchingPhotos}>
                {isFetchingPhotos ? (
                  <><Loader2 className="mr-2 h-4 w-4 animate-spin" />抓取照片中...</>
                ) : (
                  <><ImageIcon className="mr-2 h-4 w-4" />为无配图餐厅抓取 Google 照片</>
                )}
              </Button>
            )}
            {isFetchingPhotos && photoProgress.total > 0 && (
              <div className="space-y-1">
                <Progress value={(photoProgress.current / photoProgress.total) * 100} />
                <div className="text-xs text-muted-foreground">{photoProgress.current} / {photoProgress.total}</div>
              </div>
            )}
          </CardContent>
        </Card>
      )}
    </div>
  );
}
